import{_ as s,o as i,c as a,a as t}from"./chunks/framework.BHSVNLI7.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"en/tutorials/foundations/busybox-rootfs.md","filePath":"en/tutorials/foundations/busybox-rootfs.md","lastUpdated":null}'),o={name:"en/tutorials/foundations/busybox-rootfs.md"};function n(r,e,l,d,h,c){return i(),a("div",null,[...e[0]||(e[0]=[t(`<h2 id="what-we-re-doing" tabindex="-1">What We&#39;re Doing <a class="header-anchor" href="#what-we-re-doing" aria-label="Permalink to &quot;What We&#39;re Doing&quot;">​</a></h2><p>The kernel is compiled, but a kernel alone isn&#39;t enough to be useful—after booting, the kernel needs a rootfs to provide a basic user-space environment. At the very least, we need a shell to type commands into. In this article, we use BusyBox to build a minimal rootfs, package it into a cpio.gz initramfs image, and use it as the initial RAM disk when the kernel boots. Once done, we&#39;ll have all the materials needed for booting: a compiled kernel + a packaged rootfs.</p><h2 id="what-to-know" tabindex="-1">What to Know <a class="header-anchor" href="#what-to-know" aria-label="Permalink to &quot;What to Know&quot;">​</a></h2><h3 id="why-busybox" tabindex="-1">Why BusyBox <a class="header-anchor" href="#why-busybox" aria-label="Permalink to &quot;Why BusyBox&quot;">​</a></h3><p>BusyBox is the Swiss Army knife of the embedded Linux world—it packages dozens of standard Linux tools like <code>ls</code>, <code>cat</code>, <code>sh</code>, <code>mount</code>, <code>cp</code>, and <code>mv</code> into a single binary file. Through symbolic links, each &quot;command&quot; points to the same busybox executable. The benefit is a massive saving in storage space: the entire user-space toolset takes up only a few hundred KB, making it perfect for capacity-sensitive scenarios like initramfs.</p><p>Our rootfs doesn&#39;t need to be a fully functional Linux distribution. It only needs to do one thing: give us an interactive shell after booting so we can run basic commands like <code>uname -a</code>, <code>cat /proc/cpuinfo</code>, and <code>ls /sys/</code> to verify kernel functionality. BusyBox perfectly meets this need.</p><p>(A quick plug: the author vibe-coded a minimal core-binutils similar to BusyBox called CFBox. Check it out on GitHub: <a href="https://github.com/Awesome-Embedded-Learning-Studio/CFBox" target="_blank" rel="noreferrer">https://github.com/Awesome-Embedded-Learning-Studio/CFBox</a>)</p><h3 id="building-the-rootfs" tabindex="-1">Building the rootfs <a class="header-anchor" href="#building-the-rootfs" aria-label="Permalink to &quot;Building the rootfs&quot;">​</a></h3><p>The project provides an automation script, <a href="./scripts/rootfs-minimal-maker.sh">rootfs-minimal-maker.sh</a>, to handle the entire rootfs build process. Its core tasks include: compiling BusyBox (statically linked), creating the rootfs directory structure (<code>bin/</code>, <code>sbin/</code>, <code>usr/</code>, <code>proc/</code>, <code>sys/</code>, <code>dev/</code>, etc.), installing BusyBox&#39;s symbolic links, and generating the <code>/init</code> boot script. Run it like this:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ARCH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">aarch64</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./scripts/rootfs-minimal-maker.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> defconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Here, <code>ARCH=aarch64</code> is critical—it determines whether the compiled BusyBox is for ARM64. If we forget to set <code>ARCH</code>, the script won&#39;t throw an error, but it will output the rootfs to a directory with a weird path (<code>out/build_latest_/rootfs/</code>—note the empty underscore, which happens because <code>ARCH</code> is empty), and the compiled BusyBox might be for the x86 architecture. We&#39;ve actually fallen into this trap, and it&#39;s surprisingly tricky to debug.</p><p>After the build completes, let&#39;s check the rootfs directory:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/build_latest_arm64/rootfs/</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># bin/  dev/  etc/  init*  proc/  sbin/  sys/  usr/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>A minimal bootable rootfs needs these directories and files. Under <code>bin/</code> and <code>sbin/</code> are BusyBox&#39;s symbolic links, and <code>init</code> is the first user-space program executed after the kernel boots.</p><h3 id="init-the-first-user-space-program-after-kernel-boot" tabindex="-1">/init: The First User-Space Program After Kernel Boot <a class="header-anchor" href="#init-the-first-user-space-program-after-kernel-boot" aria-label="Permalink to &quot;/init: The First User-Space Program After Kernel Boot&quot;">​</a></h3><p>After completing hardware initialization, the kernel executes the <code>/init</code> program in the rootfs (assuming the kernel command line specifies <code>rdinit=/init</code>). Our <code>/init</code> is a simple shell script that does something very straightforward: it mounts <code>/proc</code>, <code>/sys</code>, and <code>/dev</code> (devtmpfs), then starts an interactive shell.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/bin/sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> proc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> proc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devtmpfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devtmpfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /bin/sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Every line here is necessary. <code>/proc</code> provides the process information and kernel parameter interface, <code>/sys</code> provides the device model and driver information, and <code>/dev</code> provides device nodes (such as <code>/dev/console</code>, <code>/dev/null</code>, etc.). If we forget to mount <code>/dev</code>, BusyBox&#39;s shell will complain about <code>can&#39;t access tty</code> when starting. The shell will still come up, but it will lack some features (like job control).</p><h3 id="packaging-as-cpio-gz" tabindex="-1">Packaging as cpio.gz <a class="header-anchor" href="#packaging-as-cpio-gz" aria-label="Permalink to &quot;Packaging as cpio.gz&quot;">​</a></h3><p>The initrd image QEMU needs is a cpio-format archive, and it must be in <code>newc</code> format—this is the standard format for kernel initramfs. Our build script already includes the packaging step, but if we need to package it manually (for example, after modifying the rootfs contents), the command is as follows:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/build_latest_arm64/rootfs</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -print0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cpio</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --null</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ov</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --format=newc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> gzip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -9</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../rootfs.cpio.gz</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Let&#39;s break down this pipeline command: <code>find . -print0</code> recursively lists all files under rootfs, separated by null bytes (to handle spaces and special characters in filenames); <code>cpio --null -ov --format=newc</code> reads these paths and packages them into a newc-format cpio archive; <code>gzip -9</code> compresses it with the maximum compression ratio, ultimately producing a <code>rootfs.cpio.gz</code> file of about 1MB.</p><p>Why static linking? When compiling BusyBox, we chose static linking (<code>CONFIG_STATIC=y</code>), which means the BusyBox executable contains all the required C library functions and doesn&#39;t depend on any external shared libraries (<code>.so</code> files). This is necessary in the initramfs scenario because our rootfs doesn&#39;t have a <code>/lib/</code> directory—if BusyBox were dynamically linked, executing <code>/init</code> after the kernel boots would fail to find the dynamic linker (<code>ld-linux-aarch64.so.1</code>) and exit with an error.</p><h2 id="try-it-yourself" tabindex="-1">Try It Yourself <a class="header-anchor" href="#try-it-yourself" aria-label="Permalink to &quot;Try It Yourself&quot;">​</a></h2><ol><li>Run <code>ARCH=aarch64 ./scripts/rootfs-minimal-maker.sh defconfig</code> to build the rootfs</li><li>Check that the <code>out/build_latest_arm64/rootfs/init</code> file exists and has execute permissions (<code>ls -l</code>)</li><li>Use <code>file out/build_latest_arm64/rootfs/bin/busybox</code> to confirm BusyBox is a statically linked ARM64 binary</li><li>Check that <code>out/build_latest_arm64/rootfs.cpio.gz</code> has been generated, and use <code>ls -lh</code> to view its size</li></ol><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h2><ul><li><a href="./scripts/rootfs-minimal-maker.sh">rootfs-minimal-maker.sh</a> — The rootfs build script; the <code>setup_rootfs()</code> function in particular shows which directories and files a minimal rootfs needs</li><li><a href="https://busybox.net/" target="_blank" rel="noreferrer">BusyBox Official Website</a> — The BusyBox project homepage and documentation</li></ul>`,27)])])}const k=s(o,[["render",n]]);export{u as __pageData,k as default};
